// Demodesk Webhook Payload: recording.transcription_postprocessed
const body = $input.first().json.body || $input.first().json;
const attrs = body.attributes || body;

const token = attrs.token || '';
const demoId = attrs.demoId || '';
const hostEmail = attrs.hostEmail || '';
const hostId = attrs.hostId || '';
const webhookUrl = attrs.url || '';
const temporaryVideoUrl = attrs.temporaryVideoUrl || '';
const aiSummary = attrs.primaryAiSummaryPlaintext || attrs.latestAiSummaryPlaintext || '';

if (!token) {
  throw new Error('Kein Recording Token im Webhook-Payload gefunden');
}

return [{
  json: {
    token,
    demoId: String(demoId),
    hostEmail,
    hostId: String(hostId),
    webhookUrl,
    temporaryVideoUrl,
    aiSummary
  }
}];

// Pruefen ob Recording bereits in Supabase existiert
const token = $json.token;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_LEADS_URL + '/rest/v1/transcripts?select=id&demodesk_token=eq.' + token + '&limit=1',
  headers: {
    'apikey': $env.SUPABASE_LEADS_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY
  }
});

const exists = Array.isArray(response) && response.length > 0;

return [{ json: { ...$json, alreadyExists: exists } }];

// Recording-Details + Transkript + Teilnehmer-Daten von Demodesk holen
// Alle API-Keys definieren (jeder Key hat nur Zugriff auf eigene Demos)
const allApiKeys = [
  $env.DEMODESK_API_KEY_LILIAN,
  $env.DEMODESK_API_KEY_THOMAS,
  $env.DEMODESK_API_KEY_PETER,
  $env.DEMODESK_API_KEY_BRANTAN,
  $env.DEMODESK_API_KEY,
].filter(Boolean);

const token = $json.token;
const demoId = $json.demoId;
let videoUrl = '';
let customerUrl = '';
let audioOnly = false;
let recordingStatus = '';

// 1. Recording-Details (funktioniert mit jedem Key)
try {
  const recording = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://demodesk.com/api/v1/recordings/${token}`,
    headers: { 'api-key': allApiKeys[0], 'Accept': 'application/json' }
  });
  const attrs = recording.data?.attributes || {};
  videoUrl = attrs.url || '';
  customerUrl = attrs.customerUrl || '';
  audioOnly = attrs.audioOnly || false;
  recordingStatus = attrs.status || '';
} catch (e) {
  videoUrl = $json.temporaryVideoUrl || '';
  customerUrl = $json.webhookUrl || '';
}

// 2. Demo-Daten mit Teilnehmern — richtigen Key finden
let participantEmail = '';
let participantName = '';
let hostName = '';
let meetingAccount = '';
let meetingStart = null;
let meetingDuration = null;
let workingKey = '';

for (const apiKey of allApiKeys) {
  try {
    const demoResp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://demodesk.com/api/v1/demos?filter[id_eq]=${demoId}&include=participants`,
      headers: { 'api-key': apiKey, 'Accept': 'application/json' }
    });
    const demos = demoResp.data || [];
    if (demos.length === 0) continue;

    // Richtigen Key gefunden!
    workingKey = apiKey;
    const demo = demos[0];
    const attrs = demo.attributes || {};
    meetingAccount = attrs.account || '';
    meetingStart = attrs.startDate || null;
    meetingDuration = attrs.duration || null;
    hostName = [attrs.userFirstName, attrs.userLastName].filter(Boolean).join(' ');

    const included = demoResp.included || [];
    const participantMap = {};
    for (const item of included) {
      if (item.type === 'participants' && item.attributes) {
        participantMap[item.id] = item.attributes;
      }
    }
    const partIds = (demo.relationships?.participants?.data || []).map(p => p.id);
    const customerParts = partIds.map(id => participantMap[id]).filter(p => p && p.permission === 'customer');
    participantEmail = customerParts.find(p => p.email)?.email || customerParts.find(p => p.displayName?.includes('@'))?.displayName || '';
    participantName = customerParts.find(p => p.fullName && p.fullName.trim() && !p.fullName.includes('@'))?.fullName || '';
    break;
  } catch (e) {
    continue;
  }
}

// 3. Transkript mit dem gefundenen Key abrufen (Fallback: Default-Key)
let transcript = '';
const transcriptKey = workingKey || allApiKeys[0];
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://demodesk.com/api/v1/recordings/${token}/transcript`,
    headers: { 'api-key': transcriptKey, 'Accept': 'text/plain' }
  });
  transcript = typeof resp === 'string' ? resp : (resp.data || JSON.stringify(resp));
} catch (e) {
  transcript = '';
}

return [{
  json: {
    token: $json.token,
    demoId: $json.demoId,
    hostEmail: $json.hostEmail,
    aiSummary: $json.aiSummary,
    videoUrl,
    customerUrl,
    audioOnly,
    recordingStatus,
    transcript,
    participantEmail,
    participantName,
    hostName,
    meetingAccount,
    meetingStart,
    meetingDuration
  }
}];

// Daten zusammenfuehren und in Supabase speichern
const meta = $('Fetch Recording Data').first().json;
let drive = {};
try {
  drive = $('Google Drive Upload').first().json || {};
} catch (e) {
  drive = {};
}
const hasDrive = drive.id && !drive.error;

const record = {
  source_type: 'demodesk',
  content: meta.transcript || '',
  call_type: 'strategiegespraech',
  url: meta.customerUrl || '',
  demodesk_token: meta.token || '',
  demodesk_demo_id: meta.demoId || '',
  recording_url: meta.videoUrl || '',
  google_drive_url: hasDrive ? (drive.webViewLink || drive.webContentLink || '') : '',
  google_drive_file_id: hasDrive ? drive.id : '',
  customer_url: meta.customerUrl || '',
  ai_summary: meta.aiSummary || '',
  audio_only: meta.audioOnly || false,
  recording_status: meta.recordingStatus || 'ready',
  participant_email: meta.participantEmail || '',
  participant_name: meta.participantName || '',
  host_name: meta.hostName || '',
  host_email: meta.hostEmail || '',
  meeting_account: meta.meetingAccount || '',
  meeting_start: meta.meetingStart || null,
  meeting_duration: meta.meetingDuration || null,
  synced_at: new Date().toISOString()
};

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_LEADS_URL + '/rest/v1/transcripts',
  headers: {
    'apikey': $env.SUPABASE_LEADS_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=representation'
  },
  body: JSON.stringify([record])
});

return [{ json: { success: true, token: meta.token, participantEmail: meta.participantEmail, hasDrive } }];
